import{_ as e,o as a,c as p,j as r,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const B=JSON.parse('{"title":"宝可梦技能—钢","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—钢.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—钢.md"}'),n={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/2.宝可梦技能机器/宝可梦技能—钢.md"};function s(o,b,_,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"宝可梦技能—钢",tabindex:"-1"},[t("宝可梦技能—钢 "),r("a",{class:"header-anchor",href:"#宝可梦技能—钢","aria-label":'Permalink to "宝可梦技能—钢"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"新世短歌031")])])],-1),d('<h1 id="宝可梦技能—钢-1" tabindex="-1">宝可梦技能—钢 <a class="header-anchor" href="#宝可梦技能—钢-1" aria-label="Permalink to &quot;宝可梦技能—钢&quot;">​</a></h1><p>宝可梦技能—钢</p><p>特别说明：若没有说明，则钢系技能中物理系技能造成的伤害均为钝击伤害，法伤技能造成的均为力场伤害。<br> 所有钢系技能皆具有【法破】特性，不在每项技能中赘述。</p><p>钢翼<br> C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：整轮动作<br> 效果：钢系物理技能，宝可梦进行一次冲锋攻击检定对目标造成挥砍伤害。本次攻击具有10点破甲、5点高速，并骰一个自然骰D10，若结果为10，则该宝可梦获得等同于其耐力属性点的天生防御，持续一个场景或将该宝可梦回收至精灵球后失效（二者取低）。</p><p>铁尾<br> C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，宝可梦进行一次近战攻击检定对目标造成钝击伤害。本次攻击具有【熔毁10】【高速10】特性。</p><p>金属爪<br> D+500<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，宝可梦进行一次近战攻击检定对目标造成挥砍伤害。本次攻击具有6点器械加值，并骰一个自然骰D10，若结果为10，则该宝可梦接下来的近战攻击检定获得2点来自技艺的附加成功（不可叠加），持续一个场景或将宝可梦回收至精灵球后失效（二者取低）。<br> 差价升级至C+1000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击获得的器械加值提升至力量属性点，并当自然骰结果为10时，额外获得的附加成功提升至4.</p><p>彗星拳<br> C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，宝可梦进行一次近战攻击检定对目标造成钝击伤害。本次攻击获得等同于宝可梦力量属性点的器械加值，并无视2点近战伤害吸收。使用本技能后骰一个自然骰D10，若结果为10，则该宝可梦的力量检定获得9点器械加值（不可叠加），持续一个场景或将宝可梦回收至精灵球后失效（二者取低）。<br> 差价升级至B+2000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能攻击所无视的近战伤害吸收提升为无视任意伤害吸收健美，并提升至8。自然骰结果为10获得的力量检定加值提升至18。</p><p>金属音<br> C+1000<br> 指挥动作：移动动作<br> 宝可梦消耗动作：移动动作<br> 效果：钢系变化技能，宝可梦进行一次施法检定对目标进行爆鸣干扰，射程15米。对手以强韧豁免进行对抗，若胜出，则对手的任意能量抗力在一回合内下降差值数（优先全能量抗力，若全能量抗力不足，则由训练家选择下降），上限为7。</p><p>铁壁<br> B+2000<br> 指挥动作：移动动作<br> 宝可梦消耗动作：移动动作<br> 效果：钢系变化技能，宝可梦进行一次使全身硬化的能量运转行为，能量流遍全身之后，该宝可梦获得等同于其耐力属性点两倍的天生防御以及基于天生防御的【坚韧】效果，持续一个场景或将宝可梦回收至精灵球后失效（二者取低）。</p><p>陀螺球<br> B+2000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，宝可梦进行一次近战攻击，让身体旋转碾压对手，其先攻比目标越低，则伤害越高，具体计算方式为，先攻比对手低10，则获得6dp加值及3点附加成功，先攻比对手低11-20，则获得11dp加值及6点附加成功，先攻比对手低20以上，则该攻击获得等同于宝可梦力量属性点的器械加值，并获得9点附加成功。</p><p>金属爆炸<br> B+2000<br> 声明动作：自由动作<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，你必须在一个战斗回合开始之前指定一个目标并发出【声明】你要使用该技能，目标会知晓本技能的实际效果，该宝可梦的先攻轮次降低至本轮最后一位，持续一轮。<br> 在宝可梦的回合开始后，宝可梦需使用金属爆炸攻击指定的目标，这次攻击具有【毁灭】与等同于目标本轮对宝可梦造成伤害值的附加成功，这是技艺加值，因此技艺获得的附加成功不能超过宝可梦耐力属性值，使用该技能后，宝可梦还可以移动至多15米的距离。</p><p>子弹拳<br> C+1000<br> 声明动作：反射动作<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，该宝可梦进行一次近战攻击检定造成钝击伤害，本次攻击具有1点来自技艺的附加成功。<br> 使用本技能必须在一个战斗轮开始之前发出【声明】，声明以后将宝可梦的先攻提高18点，持续到本轮结束。本次攻击具有【9加骰】【毁灭】特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 提升至B级效果：本次攻击附带的附加成功提升至3点，先攻提升效果提升至36点，【9加骰】提升为【8加骰】，【毁灭】提升至【湮灭】。<br> 提升至A级效果：附加成功提到7点、先攻提升效果提升至72点，具有【接触攻击】、【8加骰】、【湮灭】特性。这次攻击忽略对手的力场防御，这是一个A级的环境来源效果（视为这一拳的携带了巨幅钢系能量加成，能突破一切力场）。</p><p>镜光射击<br> D+500<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系法伤技能，该宝可梦进行一次施法攻击检定，射程15米。本次检定中附带3dp的钢系能量加值，并无视2点任意伤害减免。<br> 差价升级：C+1000<br> 差价升级后仍可使用技艺的较低级别版本。<br> 则本技能的射程提升至45米，攻击附带钢系能量加值提升至9dp，并获得1点来自技艺的附加成功。</p><p>加农光炮<br> C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系法伤技能，该宝可梦进行一次施法攻击检定，这次攻击检定+9dp的钢系能量加值，射程30米。这次攻击额外具有10破魔和5高速的特性。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击射程提升至90米，获得【能量武器】【8加骰】【湮灭】特性。攻击命中后使目标的力场防御降低9点，这是一个B级环境来源的效果，持续一个场景（本效果无法叠加）。<br> A级效果：这次攻击攻击检定附带的钢系能量加值提升为该宝可梦的施法属性值，射程提升至敏感范围。本次攻击忽略对手的力场、偏斜防御，这是一个A级的环境来源效果。</p><p>铁头<br> C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：标准动作<br> 效果：钢系物理技能，该宝可梦进行一次近战攻击检定，这次攻击获得等同于该宝可梦力量属性点的器械加值，无视目标1点任意伤害减免。<br> 差价升级至B+2000/A+4000<br> 差价升级后仍可使用技艺的较低级别版本。<br> B级效果：这次攻击无视的伤害减免提升至5，攻击命中后附带伤害值一半的恐惧点数（创伤来源），正常豁免。<br> A级效果：这次攻击命中附带的恐惧点数（创伤来源）提升至等于伤害值，正常豁免，并对目标造成S级重伤效果。</p><p>重磅冲撞<br> C+1000<br> 指挥动作：标准动作<br> 宝可梦消耗动作：移动动作+标准动作<br> 效果：钢系物理技能，宝可梦进行一次冲锋攻击。本次攻击检定中，宝可梦的体积每比对方高出一级（微型-小型-中型-大型-巨型-超巨型），便获得4点能量加值与5点破甲。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const f=e(n,[["render",s]]);export{B as __pageData,f as default};
